    private static final int READ_TIMEOUT_MS = 10000;
    private static final int MAX_REDIRECTS = 5;
    private static final int MAX_CONTENT_LENGTH = 5 * 1024 * 1024; // 5MB 上限，可按需调整

    // 仅允许的端口（-1 表示协议默认端口），可按需扩展
    private static final Set<Integer> ALLOWED_PORTS =
            Collections.unmodifiableSet(new HashSet<>(Arrays.asList(80, 443)));

