                conn.setInstanceFollowRedirects(false);
                conn.setUseCaches(false);
                conn.setConnectTimeout(CONNECT_TIMEOUT_MS);
                conn.setReadTimeout(READ_TIMEOUT_MS);
                conn.setRequestMethod("GET");
                conn.setRequestProperty("User-Agent", "RemoteResourceService/1.0");

                int status = conn.getResponseCode();

                // 处理重定向
                if (isRedirect(status)) {
                    String location = conn.getHeaderField("Location");
                    if (location == null || location.trim().isEmpty()) {
                        throw new IOException("HTTP redirect received without Location header");
                    }
                    URI next = current.resolve(location.trim()).normalize();
                    current = normalizeAndValidate(next);
                    redirects++;
