        String scheme = uri.getScheme();
        if (scheme == null) {
            throw new URISyntaxException(uri.toString(), "URI missing scheme");
        }
        String s = scheme.toLowerCase(Locale.ROOT);
        if (!"http".equals(s) && !"https".equals(s)) {
            throw new URISyntaxException(uri.toString(), "Only http/https schemes are allowed");
        }

        // 禁止包含用户凭证
        if (uri.getUserInfo() != null) {
            throw new URISyntaxException(uri.toString(), "User info in URI is not allowed");
