        String asciiHost = IDN.toASCII(host.trim());
        if (!isHostAllowed(asciiHost)) {
            throw new IOException("Prohibited host: " + host);
        }

        // 端口限制
        if (!isPortAllowed(normalized)) {
            throw new IOException("Prohibited port: " + normalized.getPort());
        }

        // 使用 ASCII host 重建 URI，避免 IDN 绕过
        try {
            normalized = new URI(
                    normalized.getScheme(),
                    null,
                    asciiHost,
                    normalized.getPort(),
                    normalized.getPath(),
                    normalized.getQuery(),
                    normalized.getFragment()
            );
        } catch (URISyntaxException e) {
            // 回退到原始 normalized，如果无法重建
        }

        return normalized;
    }

    private static boolean isPortAllowed(URI uri) {
        int port = uri.getPort();
        if (port == -1) {
            // 默认端口：根据协议允许
            return true;
        }
        return ALLOWED_PORTS.contains(port);
    }

    private static boolean isHostAllowed(String host) throws IOException {
        String lower = host.toLowerCase(Locale.ROOT);

        // 明确阻止常见本地域名
        if ("localhost".equals(lower) || lower.endsWith(".localhost")) {
            return false;
        }
        // 可选：阻止 .local 的 mDNS
        if (lower.endsWith(".local")) {
            return false;
        }

        InetAddress[] addresses = InetAddress.getAllByName(host);
        for (InetAddress addr : addresses) {
            if (isProhibitedAddress(addr)) {
                return false;
            }
        }
        return true;
    }

    private static boolean isProhibitedAddress(InetAddress addr) {
        // 通用禁止范围
        if (addr.isAnyLocalAddress()      // 0.0.0.0/8, ::
                || addr.isLoopbackAddress()   // 127.0.0.0/8, ::1
                || addr.isLinkLocalAddress()  // 169.254.0.0/16, fe80::/10
                || addr.isSiteLocalAddress()  // 10/8, 172.16/12, 192.168/16, (IPv6  fec0::/10)
                || addr.isMulticastAddress()) {
            return true;
        }

        // 额外禁止 IPv6 ULA: fc00::/7
        if (addr instanceof Inet6Address) {
            byte[] b = addr.getAddress();
            if (b != null && b.length == 16) {
                if ((b[0] & (byte) 0xFE) == (byte) 0xFC) {
                    return true;
                }
            }
            return false;
        }

        if (addr instanceof Inet4Address) {
            byte[] b = addr.getAddress();
            int v = ((b[0] & 0xFF) << 24)
                    | ((b[1] & 0xFF) << 16)
                    | ((b[2] & 0xFF) << 8)
                    | (b[3] & 0xFF);

            // 100.64.0.0/10 (CGNAT)
            if ((v & 0xFFC00000) == 0x64400000) {
                return true;
            }
            // 192.0.0.0/24 (IETF Protocol Assignments)
            if ((v & 0xFFFFFF00) == 0xC0000000) {
                return true;
            }
            // 198.18.0.0/15 (网络基准测试)
            if ((v & 0xFFFE0000) == 0xC6120000) {
                return true;
            }
            // 240.0.0.0/4 (保留地址)
            if ((v & 0xF0000000) == 0xF0000000) {
                return true;
            }
            // 云厂商/常见元数据服务
            // 169.254.169.254 (AWS/Azure/GCP)
            if ((b[0] & 0xFF) == 169 && (b[1] & 0xFF) == 254 && (b[2] & 0xFF) == 169 && (b[3] & 0xFF) == 254) {
                return true;
            }
            // 100.100.100.200 (Aliyun)
            if ((b[0] & 0xFF) == 100 && (b[1] & 0xFF) == 100 && (b[2] & 0xFF) == 100 && (b[3] & 0xFF) == 200) {
                return true;
            }
        }

        return false;
    }

    private static byte[] readFullyWithLimit(InputStream in, int maxBytes) throws IOException {
        ByteArrayOutputStream baos = new ByteArrayOutputStream(Math.min(maxBytes, 8192));
        byte[] buf = new byte[8192];
        int total = 0;
        int n;
        while ((n = in.read(buf)) != -1) {
            total += n;
            if (total > maxBytes) {
                throw new IOException("Resource exceeds maximum allowed size");
            }
            baos.write(buf, 0, n);
        }
        return baos.toByteArray();
    }
}

