            }
        }

        // IPv4 共享地址空间 100.64.0.0/10
        if (addr instanceof Inet4Address) {
            byte[] b = addr.getAddress();
            int first = b[0] & 0xFF;
            int second = b[1] & 0xFF;
            if (first == 100 && (second & 0xC0) == 0x40) { // 64-127
