        int len = hex16bytes.length();
        byte[] out = new byte[len / 2];
        for (int i = 0; i < out.length; i++) {
            int hi = Character.digit(hex16bytes.charAt(i * 2), 16);
            int lo = Character.digit(hex16bytes.charAt(i * 2 + 1), 16);
            out[i] = (byte) ((hi << 4) | lo);
        }
        return out;
    }
