        if (port == 0 || port < -1 || port > 65535) {
            return false;
        }
        return true;
    }

    private static URI resolveRedirectLocation(URI base, String location) {
        try {
            URI loc = new URI(location.trim());
            if (!loc.isAbsolute()) {
                loc = base.resolve(loc).normalize();
            } else {
                loc = loc.normalize();
            }
            return loc;
        } catch (URISyntaxException e) {
            return null;
        }
    }

    private static boolean isRedirect(int status) {
        return status == 301 || status == 302 || status == 303 || status == 307 || status == 308;
