     * 读取输入流，最多读取 maxBytes 字节。
     * 若 declaredLength > maxBytes，直接返回 null。
     * 若实际内容超过 maxBytes，也返回 null。
     */
    private static byte[] readUpToLimit(InputStream in, long declaredLength, long maxBytes) throws IOException {
        if (declaredLength > maxBytes) {
            return null;
        }
        int initialCapacity = 8192;
        if (declaredLength > 0 && declaredLength <= Integer.MAX_VALUE) {
            initialCapacity = (int) Math.min(declaredLength, maxBytes);
        }

        try (ByteArrayOutputStream out = new ByteArrayOutputStream(initialCapacity)) {
            byte[] buffer = new byte[8192];
            long total = 0L;
            int n;
            while ((n = in.read(buffer)) != -1) {
                total += n;
                if (total > maxBytes) {
                    return null;
                }
                out.write(buffer, 0, n);
            }
            return out.toByteArray();
        }
    }

    private static void closeQuietly(InputStream in) {
        if (in == null) return;
        try {
            in.close();
        } catch (IOException ignore) {
        }
    }
}

