                boolean isV4Mapped =
                        b[0] == 0x00 && b[1] == 0x00 && b[2] == 0x00 && b[3] == 0x00 &&
                        b[4] == 0x00 && b[5] == 0x00 && b[6] == 0x00 && b[7] == 0x00 &&
                        b[8] == 0x00 && b[9] == 0x00 && b[10] == (byte) 0xff && b[11] == (byte) 0xff;
