        private final byte[] network;
        private final byte[] mask;

        CidrBlock(String cidr) throws Exception {
            String[] parts = cidr.trim().split("/");
            if (parts.length != 2) throw new IllegalArgumentException("Invalid CIDR: " + cidr);
            InetAddress netAddr = InetAddress.getByName(parts[0]);
            int prefix = Integer.parseInt(parts[1]);
            this.network = netAddr.getAddress();
            int totalBits = network.length * 8;
            if (prefix < 0 || prefix > totalBits) throw new IllegalArgumentException("Invalid prefix: " + prefix);

            this.mask = new byte[network.length];
            int fullBytes = prefix / 8;
            int remainingBits = prefix % 8;
            for (int i = 0; i < fullBytes; i++) {
                mask[i] = (byte) 0xFF;
            }
            if (remainingBits > 0) {
                int value = 0xFF << (8 - remainingBits);
                mask[fullBytes] = (byte) value;
            }
            // 其余字节默认为0

            // 规范化：将network按mask归零主机位
            for (int i = 0; i < network.length; i++) {
                network[i] = (byte) (network[i] & mask[i]);
