        }

        boolean matches(InetAddress addr) {
            byte[] candidate = addr.getAddress();
            if (candidate.length != network.length) {
                return false;
            }
            for (int i = 0; i < candidate.length; i++) {
                int a = candidate[i] & mask[i];
                int b = network[i] & 0xFF;
                if (a != b) return false;
            }
            return true;
        }
    }
}

